async (params, browser) => {
  // Open page
  await browser.open(`https://letterboxd.com/${params.username}/`)

  // Wait for content
  await browser.waitForSelector('h1, div.profile-summary, h4.profile-statistic', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const name = document.querySelector('meta[property="og:title"]')?.getAttribute('content')||document.querySelector('h1')?.textContent?.trim()||''; const bio = document.querySelector('meta[property="og:description"]')?.getAttribute('content')||''; const location = document.querySelector('div.profile-metadata div.metadatum')?.textContent?.trim()||''; const stats = {}; document.querySelectorAll('h4.profile-statistic').forEach(s => { const a = s.querySelector('a'); const spans = s.querySelectorAll('span'); const val = a?a.textContent.trim():(spans[0]?spans[0].textContent.trim():''); const lbl = spans.length>1?spans[spans.length-1].textContent.trim().toLowerCase():''; if(lbl&&val) stats[lbl]=val; }); const favs = Array.from(document.querySelectorAll('section#favourites ul.poster-list li img, section#favourites .poster-container img')).slice(0,4).map(img=>img.getAttribute('alt')||''); return { username: '' + params.username + '', name, bio, location, stats, favorite_films: favs, url: window.location.href }`)

  return page_data
}
